"""
MKT Original Commentary — Ezekiel chapters 33–35
Run: python3 scripts/zc-original-ezekiel-33-35-fill.py

Source data used:
- data/interlinear/ezekiel.json
- data/translation/glossary-hebrew.json (tzofeh, ra'ah, brit shalom, etc.)
- BDB and HALOT for key terms

Key decisions in this range:
- 33:11 'as I live' oath: divine will for life, not death, is the pivot of the whole book
- 33:21-22 mouth-opening: narrative hinge between judgment and restoration sections
- 34:23-24 'David my servant': treated as messianic promise (singular shepherd to come)
- 34:25 brit shalom: covenant of peace as the eschatological restoration covenant
- ch35 Edom: representative of all nations hostile to Israel's restoration
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

EZEKIEL_ORIGINAL = {
"33": {
    "1": '<p>New oracle-reception formula. Chapter 33 is structurally pivotal: it reopens the watchman commission of chapter 3 (vv. 1-9), revisits the individual accountability principles of chapter 18 (vv. 12-20), and is anchored by the news of Jerusalem\'s fall (v. 21). Chapters 1-32 are primarily judgment; from chapter 33 onward, restoration becomes the dominant register.</p>',
    "2": '<p><strong>ben-adam daber el-bnei amecha</strong> (\'son of man, speak to your people\'): the shift from <em>beit Yisrael</em> (house of Israel) to <em>amecha</em> (your people) is subtle but significant — the prophet has a personal covenant relationship with the community to whom he speaks. The watchman (<em>tzofeh</em>) analogy returns from 3:17: a man from among a people, posted at the walls, responsible for alarm. The responsibility is communal but the appointment is individual.</p>',
    "3": '<p><strong>ura\'ah et-hacherev ba\'ah al-ha\'aretz</strong> (\'and he sees the sword coming upon the land\'): the watchman\'s function is perception followed by communication — <em>taqe\'a beshofar</em> (blow the trumpet). The shofar as the alarm instrument carries the weight of covenant-calling throughout the Hebrew Bible: the same instrument used for Sinai (Ex 19:16-19), jubilee (Lev 25:9), and Joel\'s eschatological alarm (Joel 2:1). The watchman\'s trumpet is a prophetic voice.</p>',
    "4": '<p><strong>damav be\'rosho yihyeh</strong> (\'his blood will be on his own head\'): the legal principle of transferred responsibility — when the alarm is sounded and the person fails to act, the watchman\'s duty is discharged and the unresponsive person bears their own consequence. The \'blood on the head\' idiom (cf. Josh 2:19; 2 Sam 1:16; Acts 18:6) is a standard Ancient Near Eastern legal formula for placing responsibility.</p>',
    "5": '<p><strong>hu shama et-qol hashofar velo nizhar</strong> (\'he heard the sound of the trumpet and was not warned\'): the paradox of hearing-without-heeding — the ear received the signal but the will did not respond. <em>Damav bo yihyeh</em> (\'his blood will be on himself\'): the legal accountability is total. The watchman who warns has done everything required; the hearer who ignores bears all responsibility. This creates the framework for Ezekiel\'s ministry: he sounds the alarm; the response belongs to each individual.</p>',
    "6": '<p><strong>vedamav midayav edrosh</strong> (\'and his blood I will require from the watchman\'s hand\'): the reverse case — the watchman who fails to warn is held responsible for the deaths that result. <em>Midam</em> is here plural (bloods) — the accumulated deaths resulting from the failure to warn. The legal language makes Ezekiel\'s prophetic ministry a matter of life and death not merely for his audience but for himself: silence is complicity.</p>',
    "7": '<p><strong>uven-adam tzofeh natati lecha levet Yisrael</strong> (\'and you, son of man, I have made you a watchman for the house of Israel\'): the application of the general watchman-principle to Ezekiel personally. The repetition of the watchman commission from 3:17 in nearly identical terms at the book\'s structural midpoint reminds the reader (and Ezekiel) that the initial commission has not expired. With Jerusalem fallen, the prophetic watchman-role continues into the restoration era.</p>',
    "8": '<p><strong>be\'omri lerasha YHWH mot tamut</strong> (\'when I say to the wicked man, "Wicked one, you shall surely die"\') — the legal formula <em>mot tamut</em> (dying you shall die, a doubled infinitive absolute for certainty). The watchman\'s failure to speak this warning makes him complicit in the death that results. <em>Damav midayav edrosh</em>: YHWH holds Ezekiel responsible. The weight of the prophetic office is that silence kills.</p>',
    "9": '<p><strong>ve\'atah ki-hizaharta rasha midarkav leshuv mimenna velo-shav</strong> (\'but if you warn the wicked man to turn from his way and he does not turn\'): the watchman\'s discharge: if the warning is given and refused, the watchman is free. <em>Bedamav yamut</em> (\'in his blood he will die\') — his refusal to turn seals his fate; the blood is entirely his own. <em>Ve\'atah nafshecha hitzalta</em> (\'but you — your life you will have saved\'): Ezekiel\'s personal liberation from legal responsibility when he faithfully warns.</p>',
    "10": '<p><strong>ben-adam emor el-beit Yisrael</strong> (\'son of man, say to the house of Israel\'): the exiles\' complaint — <em>avoneinu va\'chata\'teinu aleinu</em> (\'our transgressions and our sins are upon us\'). The weight metaphor: sin and iniquity as a burden pressing down. <em>Umah niqeh</em> (\'how can we live?\'): the question of despair — if the covenant curses have fully fallen and there is no reversal, survival is impossible. The question prepares for the stunning divine answer of v. 11.</p>',
    "11": '<p><strong>chai-ani ne\'um Adonai YHWH im-echpatz bemot harasha</strong> (\'as I live, declares the Lord YHWH, I do not desire/take pleasure in the death of the wicked\'): the most theologically important verse in the chapter — perhaps in the book. The divine oath by YHWH\'s own life (<em>chai-ani</em>) guarantees its absolute truth. <em>Echpatz</em> (to desire, delight in) — YHWH\'s <em>chefetz</em> (delight/pleasure) is not judgment but restoration. <em>Ki im-beshuv rasha midarkav vachayah</em> (\'but rather in the wicked man turning from his way and living\'): the teshuvah-formula — turning (<em>shuv</em>) as the path to life. <em>Shuvu shuvu midarkechem hara\'im</em> (\'turn! turn from your evil ways!\'): the doubled imperative of urgency.</p>',
    "12": '<p><strong>tzidqat hatzaddiq lo tatzilenu</strong> (\'the righteousness of the righteous will not deliver him\'): the individual accountability principle (cf. ch 18) — accumulated prior righteousness does not create a permanent credit balance. <em>Veresha\' harasha lo yikashel bo</em> (\'and the wickedness of the wicked will not cause him to stumble when he turns from it\'): accumulated wickedness does not permanently disqualify. The moral condition at the moment of action determines destiny — not the accumulated record.</p>',
    "13": '<p><strong>be\'omri latzaddiq chayoh yichyeh</strong> (\'when I say to the righteous man, "You shall surely live"\') — <em>chayoh yichyeh</em>, the doubled infinitive absolute of certainty. The danger named: if the righteous person trusts in the promise and then commits evil — <em>kol-tzidqotav lo tizakarnah</em> (\'none of his righteous acts will be remembered\'). The divine accounting system is not cumulative but present-tense: the dominant direction of the will at any moment determines covenantal standing.</p>',
    "14": '<p><strong>uvea\'omri larasha mot tamut veshuv mechata\'to</strong> (\'when I say to the wicked man, "You shall surely die," but he turns from his sin\'): the pivot case — the condemned man who turns. What the legal verdict declares (death) is reversed by the turn. <em>Ve\'asah mishpat utzedaqah</em> (\'and does justice and righteousness\'): two terms for the same thing from different angles — <em>mishpat</em> (right legal action) and <em>tzedaqah</em> (righteous moral standing). The doublet covers both legal and relational dimensions of covenant faithfulness.</p>',
    "15": '<p><strong>chavol yashuv rasha yashiv</strong> (\'if the wicked man restores the pledge\'): specific acts of restitution — <em>gezelah yashlem</em> (repay what was stolen), <em>bechuqot hachayim halach</em> (walk in the statutes of life). The abstract principle of \'turning\' is grounded in specific acts of restitution. Without concrete behavioral change, \'repentance\' is merely verbal. The statutes of life (<em>chuqqot hachayim</em>) — Torah as the revealed path to life, not merely rules to obey.</p>',
    "16": '<p><strong>kol-chata\'av asher chata lo yizakru lo</strong> (\'all the sins he sinned will not be remembered against him\'): the divine forgetting of sin upon genuine repentance. The theological weight here is extraordinary: YHWH actively does not remember — not merely forgives but ceases to count. This anticipates the new covenant formula of Jeremiah 31:34 (<em>velo-ezkor od</em>, \'and I will remember no more\'). <em>Mishpat utzedaqah asah chayoh yichyeh</em>: the doublet of justice-righteousness again.</p>',
    "17": '<p><strong>va\'omru bnei amecha lo yitaken derekh Adonai</strong> (\'and your people say, "The way of the Lord is not fair/straight"\') — the accusation against YHWH\'s justice. <em>Tiqen</em> (to be right/level/fair): the same accusation from 18:25 and 18:29 — YHWH\'s ways are said to be unequal (lo-yitqanu). The accusation presupposes a human standard of justice by which YHWH\'s actions can be judged. Ezekiel\'s response is to reverse the accusation: it is Israel\'s ways that are unequal.</p>',
    "18": '<p><strong>beshov tzaddiq mitzidqato ve\'asah aval vameth bahem</strong> (\'when a righteous man turns from his righteousness and does wrong, he will die by it\'): the principle stated again in its application. The verb <em>meth bahem</em> (dies by them) — the sins become the mechanism of death. The righteous person who turns to evil does not merely face future punishment; the evil itself is lethal, carrying death within it.</p>',
    "19": '<p><strong>uveshov rasha miresha\'o va\'asah mishpat utzedaqah</strong> (\'and when the wicked man turns from his wickedness and does justice and righteousness\'): the symmetrical case. <em>Hu yachieh alehem</em> (\'he will live by/because of them\'): the righteous acts become the mechanism of life. The verb <em>yichyeh</em> (he will live) answers the desperate question of v. 10: \'how can we live?\' — by turning and doing justice and righteousness. The answer is simple, costly, and completely accessible to every individual.</p>',
    "20": '<p><strong>va\'omarten lo yitaken derekh Adonai</strong> (\'you say, "The way of the Lord is not equal"\') — final repetition of the accusation, now answered definitively. <em>Ish kedrakav ishpot etchem</em> (\'I will judge each of you according to his ways\'): the individual judgment principle as the seal. YHWH\'s equality is not abstract impartiality but personal accountability — each person judged by their own path. The defense of divine justice is the affirmation of individual moral responsibility.</p>',
    "21": '<p><strong>bayom chamishi le\'asarah lachodesh bishnat shtem-esreh</strong> (\'in the fifth day of the tenth month, in the twelfth year\'): the precise date marks the most dramatic moment in the book — the arrival of the survivor from Jerusalem. <em>Ba-elai happalit</em> (\'the fugitive/survivor came to me\'): <em>palit</em> (one who has escaped) — the technical term for a survivor of catastrophe. <em>Hukkatah Yerushalayim</em> (\'Jerusalem has been struck\'): the single sentence that is the axis of the entire book. The judgment oracles (1-24) have culminated; the restoration oracles (25-48) now begin their context.</p>',
    "22": '<p><strong>veyad YHWH haytah elai ba\'erev lifnei bo happalit</strong> (\'and the hand of YHWH was upon me in the evening before the arrival of the survivor\'): YHWH prepares Ezekiel supernaturally the evening before the news arrives — the divine communication precedes the human messenger. <em>Uftach et-pi</em> (\'and he opened my mouth\'): Ezekiel\'s mouth had been sealed since 3:26 — the dumbness that marked his prophetic restraint during the judgment period. Now it is opened. The new era of speech begins before the news arrives, signaling that YHWH orchestrates both the silence and the speaking.</p>',
    "23": '<p>New oracle following the arrival of the news. The people who remained in the land (not exiled) are addressed — they have appropriated the Abrahamic promise to justify possessing the land while the exiles are gone.</p>',
    "24": '<p><strong>yoshvei hecharvot ha\'el al-admat Yisrael</strong> (\'those who live in those ruins on the land of Israel\'): the remaining population in the land. Their theological argument: <em>Avraham echad hayah vayyiresh et-ha\'aretz</em> (\'Abraham was one and he possessed the land\'): if the solitary Abraham inherited, how much more do we who are many. The use of Abraham as a precedent is a specific misapplication of the promise — the Abrahamic covenant promised the land to Abraham\'s descendants, not to those who remain after the faithful are exiled.</p>',
    "25": '<p><strong>al-hadam ta\'achelu</strong> (\'you eat on/over blood\'): the specific violations of the remaining population — eating with blood (prohibited in Gen 9:4; Lev 17:10-14), idolatry (<em>ve\'eineihem ta\'su el-gilluleichem</em>), murder (<em>vedam tishpeku</em>), all while claiming the land by inheritance. The combination of covenant violations disqualifies them from the very inheritance they claim. The Abrahamic promise is conditional on covenant faithfulness.</p>',
    "26": '<p><strong>amadtem al-charbechem asitem to\'evah</strong> (\'you stand on your sword, you have done abomination\'): standing on the sword — living by violence — as a defining characteristic. The acts of violence (murder, sexual violence implied by <em>ish et-eshet re\'ehu timme\'u</em>), idolatry, and bloodshed are the grounds for disqualification from the inheritance. Possession of land without Torah-faithfulness is illegitimate in the covenant framework.</p>',
    "27": '<p><strong>koh tomar lahem</strong> (\'thus you shall say to them\'): the specific judgment on the remnant — those in the ruins will fall by sword, those in the open field to animals, those in strongholds will die by pestilence. The full triad of judgment (sword, pestilence, famine/wild animals) from chapters 5-6 is now applied to the remnant. No category escapes; the completeness of judgment matches the completeness of apostasy.</p>',
    "28": '<p><strong>venatatiti et-ha\'aretz shemamah umeshimamah</strong> (\'I will make the land a desolation and a waste\'): <em>shemamah umeshimamah</em> — the doubled desolation (cognate words for emphasis). The ga\'on uzza Israel (\'pride of her strength\') will cease — the same phrase used in Lev 26:19 in the list of covenant curses. The land itself becomes uninhabited, the ultimate covenant curse (Lev 26:33).</p>',
    "29": '<p><strong>veyad\'u ki-ani YHWH betiteni et-ha\'aretz shemamah</strong> (\'and they will know that I am YHWH when I make the land a desolation\'): the refrain-formula again, but now pointing toward future recognition. Even the desolation serves YHWH\'s revelatory purpose — not merely punishment but the establishment of covenant truth for those who survive to comprehend it.</p>',
    "30": '<p><strong>ve\'atah ben-adam bnei amecha hamitdabrim becha etzel hakirot</strong> (\'and you, son of man, your people who talk about you by the walls\'): the problem of performative piety — the exiles gathering communally to hear Ezekiel as a kind of entertainment. <em>Ve\'omer ish el-achiv</em> (\'and each one says to his brother\'): word about Ezekiel spreads through the community. <em>Bo-na ushemu ma-haddavar hayotze me\'et YHWH</em> (\'come and hear what the word is that goes out from YHWH\'): the intellectual curiosity about prophetic content without obedient response.</p>',
    "31": '<p><strong>uvau elecha kimevo am</strong> (\'they come to you as a people comes\'): the formal gathering of a religious audience. <em>Veyashvu lefanecha ami</em> (\'my people sit before you\'): they identify as \'my people\' — the covenant language is used. <em>Veshamu et-devarecha</em> (\'and they hear your words\'): hearing (<em>shama\'</em>) without the covenantal dimension of obedience. <em>Ve\'otam lo ya\'asu</em> (\'but they do not do them\'): the hearing-doing gap — what James 1:22-25 calls being \'hearers only.\' <em>Ki agavim befithem</em> (\'for they are like love-songs on their lips\'): Ezekiel\'s words are aesthetically appreciated as <em>shir agavim</em> (love song) — beautiful language without moral force.</p>',
    "32": '<p><strong>vehineka lahem keshir agavim</strong> (\'and you are to them like a love song\'): <em>shir agavim</em> — erotic/romantic song, beautiful but not binding. <em>Yefeh qol umentiv naggen</em> (\'beautiful of voice and skilled in playing\'): Ezekiel is experienced as an aesthetic performance — appreciated for craft and beauty, not transformed by content. The passage is a devastating analysis of religious consumerism: the audience receives the word as entertainment while rejecting it as command. <em>Ushe\'amu et-devarecha</em> (\'they hear your words\') but <em>ve\'otam einam osim</em> (\'and they do not do them\').</p>',
    "33": '<p><strong>uvevoa\'ah uvevoa\'ah uhinenah ba\'ah</strong> (\'and when it comes — and it will come — then they will know\'): the eschatological guarantee — when Ezekiel\'s prophesied events materialize, the entertainment-hearers will finally know that a prophet was among them. <em>Ki navi hayah betocham</em> (\'that a prophet had been in their midst\'): the past tense in the prediction — when it comes true, they will say \'there was a prophet among us.\' The recognition arrives after, not before, the fulfillment. Truth often convinces only retrospectively.</p>'
},
"34": {
    "1": '<p>New oracle. Chapter 34 is the great shepherd passage of Ezekiel — the indictment of Israel\'s failed shepherds (kings, priests, and leaders) followed by YHWH\'s declaration that he himself will shepherd Israel, culminating in the promise of David my servant as the eschatological shepherd-prince.</p>',
    "2": '<p><strong>hinneh anochi el-haro\'im</strong> (\'I am against the shepherds\'): the prophetic confrontation formula <em>hinneni elekha</em> (I am against you) — used for Gog (38:3), Tyre (26:3), Egypt (29:3), and here for Israel\'s shepherds. The same formula for Israel\'s leaders as for pagan nations: they have failed so completely as to be indistinguishable, in YHWH\'s covenantal reckoning, from the enemies of Israel. <em>Ra\'u et-ha\'eder</em> (\'they shepherd the flock\'): the charge — shepherds who only fed themselves.</p>',
    "3": '<p><strong>et-hacheleiv tocheilu ve\'et-hatzemer tilbashu</strong> (\'the fat you eat and the wool you wear\'): the specific economic exploitation — taking the produce of the flock (fat/milk, wool) without caring for the animals. <em>Ha\'berirah tizbachu</em> (\'the sleek ones you slaughter\'): the best of the flock consumed for the shepherds\' own tables. <em>Et-hatzon lo tiru\'u</em> (\'the flock you do not shepherd\'): the inversion of the shepherd\'s role — consuming rather than serving.</p>',
    "4": '<p><strong>et-hachallot lo chizaqtem ve\'et-hachola lo-ripe\'item</strong> (\'the weak you have not strengthened, the sick you have not healed\'): the four-fold failure — not strengthening the weak, not healing the sick, not binding the broken, not returning the strayed. <em>Et-hanidachat lo hashevotm</em> (\'the driven-away you have not brought back\'): <em>nidachat</em> (the driven/banished) — those scattered by force, including the exiles themselves. <em>Et-ha\'avudat lo dirashem</em> (\'the lost you have not sought\'): the seeking function of the shepherd — to actively pursue the lost, not merely care for those who remain.</p>',
    "5": '<p><strong>vatifutzena mibeli ro\'eh</strong> (\'and they scattered because there was no shepherd\'): the consequence of pastoral failure is directly the scattering of the flock. <em>Vatihyena le\'oclah lechol-chayat hassadeh</em> (\'they became food for every wild animal\'): when the shepherd withdraws protection, predators move in. The sheep\'s vulnerability is not their fault but the shepherd\'s failure. The political meaning is transparent: Israel\'s exile is the direct result of corrupt leadership.</p>',
    "6": '<p><strong>yittu tzoni bechol-heharim</strong> (\'my flock wanders on all the mountains\'): YHWH calls Israel <em>tzoni</em> (my flock) — possessive, covenantal. The wandering on mountains and hills echoes the bamot apostasy — the high places where false worship happened are also the hills where the scattered flock grazes without direction. <em>Ve\'ein dorresh ve\'ein mevaqesh</em> (\'and there is no one who searches and no one who seeks\'): the failed shepherds are indicted by their absence from the two defining activities of pastoral care — searching and seeking.</p>',
    "7": '<p>Direct address to the shepherds. The second person masculine plural shifts to the indicted leaders specifically. The formula <em>lachen ro\'im shim\'u devar YHWH</em> (\'therefore, O shepherds, hear the word of YHWH\') frames what follows as legal testimony — they are called to hear the divine verdict on their conduct.</p>',
    "8": '<p><strong>chai-ani</strong> (\'as I live\'): the divine oath sealing the following statement with ultimate authority. <em>Im-lo ya\'an heyot tzoni levaz</em> (\'if it is not because my flock has become plunder\'): the swearing formula of divine resolve. <em>Vatihyena tzoni le\'ochla lechol-chayat hassadeh mei\'ayin ro\'eh</em> (\'my flock became food for all the wild animals, without a shepherd\'): the accusation against the shepherds is grounded in the documented evidence — YHWH has observed his flock\'s condition.</p>',
    "9": '<p>The repetition of the summons to \'hear the word of YHWH\' signals the formal legal proceeding. The shephalim (shepherds/leaders) are being tried in the divine court. The pattern of accusation — you have not sought, you have not strengthened, you have not returned — is the evidence presented at the trial.</p>',
    "10": '<p><strong>hinneni el-haro\'im vedrashhti et-tzoni miyadam</strong> (\'I am against the shepherds and I will require my flock from their hand\'): <em>darash</em> (to seek, require, hold accountable) — the same verb used for blood-accountability (9:1; 33:6). YHWH \'requires\' the flock from the shepherds\' hands: they were entrusted with the flock; now the owner demands an accounting. <em>Vehishbatti et-haro\'im mir\'ot tzon</em> (\'I will cause the shepherds to cease from shepherding the flock\'): the Davidic/royal line of leadership is terminated — the shepherds\' commission is revoked.</p>',
    "11": '<p><strong>ki koh amar Adonai YHWH hinneni ani-udarashti et-tzoni uviqashtim</strong> (\'for thus says the Lord YHWH: I myself will search for my flock and seek them out\'): the dramatic pivot — the shift from \'I am against the shepherds\' to \'I myself will shepherd.\' The emphatic <em>ani-udarashti</em> (\'I myself will seek\') makes YHWH the direct replacement of the failed human shepherds. No intermediate human shepherd is mentioned here — YHWH takes the task personally. This is one of the most direct statements of divine pastoral action in the entire Hebrew Bible.</p>',
    "12": '<p><strong>keiro\'eh edro beyom heyoto veton-tzone nifzarot</strong> (\'as a shepherd inspects his flock on a day when he is among his scattered sheep\'): <em>nifzarot</em> (scattered/dispersed) — the diaspora condition. YHWH will seek out the scattered ones (<em>ken avaqesh et-tzoni</em>) from all the places they have been scattered — with the specific mention of <em>yom anan va\'arafel</em> (\'the cloudy and dark day\'): the day of the exile, defined by divine hiddenness, is the specific context of YHWH\'s seeking activity.</p>',
    "13": '<p><strong>vehiotzetim min-ha\'amim</strong> (\'I will bring them out from the peoples\'): the gathering-from-exile as a second Exodus. <em>Uqibbatzttim min-ha\'aratsot</em> (\'and gather them from the lands\'): a universal ingathering — not just from Babylon but from all nations. The list of terrains — mountains, valleys, watercourses, inhabited places — mirrors the comprehensive scattering described earlier: the seeking is as comprehensive as the dispersal was total.</p>',
    "14": '<p><strong>bimra\'eh tov ir\'em</strong> (\'in a good pasture I will shepherd them\'): <em>mera\'eh tov</em> (good pasture/feeding place) — the pastoral ideal of rest and abundance. <em>Vehar marom Yisrael yihyeh ne\'vehem</em> (\'and on the high mountains of Israel their fold will be\'): <em>ne\'veh</em> (dwelling place, fold) — the settled, secure community. The same mountains where the scattered flock wandered without a shepherd (v.6) become the home pasture. <em>Sham tirbatznah</em> (\'there they will lie down\'): rest in abundance as the sign of restored wellbeing.</p>',
    "15": '<p><strong>ani er\'eh tzoni ve\'ani arbitzem ne\'um Adonai YHWH</strong> (\'I myself will shepherd my flock and I myself will make them lie down, declares the Lord YHWH\'): the doubly emphatic <em>ani... ani</em> (I... I) — YHWH as the personal shepherd who does both the feeding and the settling. The resting of the flock (<em>arbitzem</em>) is the image of complete security — the posture of animals that have no fear of predators. Compare Psalm 23:2 and John 10:11-16 where the same vocabulary structures the good shepherd imagery.</p>',
    "16": '<p><strong>et-ha\'ovedet avaqesh ve\'et-hanidachat ashiv</strong> (\'the lost I will seek and the driven away I will bring back\'): the fourfold restoration program — seeking the lost, returning the strayed, binding the broken (<em>lashevurah echavesh</em>), strengthening the sick (<em>vachalah achazzeq</em>). These are the precise pastoral activities the failed shepherds of v.4 did not perform. YHWH does what the human shepherds refused to do. <em>Ve\'et-hashmenah ve\'et-hachazaqah ashmed</em> (\'but the fat and the strong I will destroy\'): the judgment element within the restoration — the powerful exploiters within the flock are not preserved in the restoration.</p>',
    "17": '<p><strong>uve\'atten tzoni koh amar Adonai YHWH hinneni shofet</strong> (\'and as for you, my flock, thus says the Lord YHWH: I am judging\'): the judicial address shifts to the flock itself. The judgment is now between members of the community — not just between the shepherds and YHWH. <em>Bein seh laseh laelim velatayishim</em> (\'between sheep and sheep, between rams and he-goats\'): distinctions within the flock — the powerful members who exploited the weak. The shepherd who protects also judges within the flock.</p>',
    "18": '<p><strong>hame\'at miqem mira\'eh tov tiruu</strong> (\'is it too little for you that you graze on the good pasture\'): the indictment against the strong within the flock — they consume the best pasture, then trample what remains; they drink the clear water, then muddy the rest with their feet. The image is of resource hoarding and deliberate degradation of communal goods. What the powerful don\'t use themselves, they destroy for others.</p>',
    "19": '<p><strong>vetzon mira\'ai mirmesteihem tir\'ena</strong> (\'and my flock eats what your feet have trampled\'): the weak flock suffers from the strong\'s waste. The pastoral imagery captures the dynamics of social inequality: the poor eat what the rich leave after trampling, drink the muddy water after the powerful have drunk their fill. This is the flock-level equivalent of the shepherd-level exploitation described in vv. 3-4.</p>',
    "20": '<p><strong>lachen koh amar Adonai YHWH eleichem</strong> (\'therefore thus says the Lord YHWH to you\'): the judicial verdict begins. <em>Hinneni ani shafatti bein seh biriyah uvein seh razah</em> (\'I myself will judge between the fat sheep and the lean sheep\'): YHWH takes the role of divine judge within the restored community — not merely restoring the flock from outside enemies but adjudicating internal inequities.</p>',
    "21": '<p><strong>ya\'an betzad uvechatel tidehu</strong> (\'because with flank and shoulder you have pushed\'): the physical aggression of the strong against the weak — pushing with flank and shoulder, butting with horns. <em>Ad asher pitzartem et-kol-hachallot</em> (\'until you scattered all the sick ones\'): the weak members of the community have been driven out by the aggressive behavior of the strong. The pastoral metaphor captures real economic and social dynamics within the exilic community.</p>',
    "22": '<p><strong>vehoshati le\'tzoni velo-tihyena od lavaz</strong> (\'I will save my flock so they will no longer be plunder\'): the divine rescue declared — the condition of being prey ends. <em>Veshafatti bein seh laseh</em> (\'and I will judge between sheep and sheep\'): the intra-community justice that guarantees the weak are protected from the strong within the restored flock. The good shepherd both protects from external predators and maintains internal justice.</p>',
    "23": '<p><strong>vahaqimoti aleihem ro\'eh echad</strong> (\'and I will raise up over them a single shepherd\'): <em>ro\'eh echad</em> — one shepherd, singular. <em>Ve\'ro\'ah ethen</em> (\'and he will shepherd them\'): the subject unexplained — then named: <em>avdi David</em> (\'my servant David\'). The Davidic covenant promise (2 Sam 7:12-13) here made eschatological — not David returned but a David-figure yet to come. <em>Hu yir\'em vehu yihyeh lahem lero\'eh</em> (\'he will shepherd them and he will be their shepherd\'): the doubled role — doing the shepherding and being the shepherd — emphasizes identity, not merely function.</p>',
    "24": '<p><strong>va\'ani YHWH ehyeh lahem le\'Elohim ve\'avdi David nasi betocham</strong> (\'and I, YHWH, will be their God and my servant David will be a prince among them\'): the covenant formula completed — <em>YHWH le\'Elohim</em> (YHWH as God) and <em>am</em> (people, implied from context). The Davidic figure is named <em>nasi</em> (prince/leader) rather than <em>melek</em> (king) — a distinction Ezekiel maintains throughout (chs 44-46), perhaps to distinguish the eschatological Davidic ruler from the discredited kings of Israel\'s history. <em>Ani YHWH dibarti</em> (\'I, YHWH, have spoken\'): the inviolable divine word sealing the promise.</p>',
    "25": '<p><strong>vekarati lahem brit shalom</strong> (\'and I will make with them a covenant of peace\'): <em>brit shalom</em> — the covenant of peace, appearing here and in 37:26 in Ezekiel (also Num 25:12; Isa 54:10; Mal 2:5). <em>Shalom</em> in the covenant context is not merely \'peace\' but the complete well-being of the covenant relationship restored. <em>Vehishbatti chayah ra\'ah min-ha\'aretz</em> (\'I will eliminate dangerous animals from the land\'): the restoration of safety in the land — the predators that plagued the flock when the shepherd was absent are removed.</p>',
    "26": '<p><strong>unatatti otam usevivot giv\'ati berakhah</strong> (\'and I will make them and the places around my hill a blessing\'): <em>berakhah</em> (blessing) as the defining characteristic of the restored land. <em>Vehora\'deti haggeshem be\'itto</em> (\'and I will send down rain in its season\'): the seasonal rain as covenant blessing (Lev 26:4; Deut 11:14) restored. <em>Gishme verakhah yihyu</em> (\'rains of blessing there will be\'): the Hebrew plays on the sound — <em>gashm</em> (rain) connected to <em>berakhah</em> (blessing) — the material blessing is itself a form of divine speech.</p>',
    "27": '<p><strong>veyitan etz hassadeh et-piryou</strong> (\'and the tree of the field will give its fruit\'): the restoration of agricultural fertility — the reversal of the covenant curses of Leviticus 26:20 (\'your trees will give no fruit\') and Deuteronomy 28:40-42. <em>Veyad\'u ki-ani YHWH beshivri et-motot ullam</em> (\'and they will know that I am YHWH when I break the bars of their yoke\'): the broken yoke as liberation from Babylonian domination — the servitude symbolized by the yoke Ezekiel wore as a sign act (ch 4).</p>',
    "28": '<p><strong>velo-yihyu od bevaz lagoyim</strong> (\'and they will no longer be plunder for the nations\'): the reversal of the condition described in v.5 and v.22. <em>Uvat-ha\'aretz lo tochlem od</em> (\'and the wild animals of the land will not devour them any more\'): both human predators (nations) and environmental predators (wild animals) are eliminated from the picture of restoration. <em>Veyashvu lavetach ve\'ein macharid</em> (\'and they will dwell securely with none to make them afraid\'): the <em>lavetach</em> (security) formula from Lev 26:5 — the covenant blessing of unafraid habitation restored.</p>',
    "29": '<p><strong>vehaqimoti lahem matta leshm</strong> (\'and I will raise up for them a planting for a name/renown\'): <em>matta</em> (planting, cutting, shoot) — the agricultural image of divine planting. <em>Leshm</em> can mean \'for a name\' or \'for renown\' — the planted community that will be the glory of the restored land. <em>Velo-yihyu od asufei ra\'av ba\'aretz</em> (\'and they will no longer be gathered by famine in the land\'): the famine that drove scattered Israel is ended. The planted people (<em>matta</em>) deliberately echoes the agricultural restoration throughout — YHWH as the divine gardener.</p>',
    "30": '<p><strong>veyad\'u ki-ani YHWH Eloheihem ittam</strong> (\'and they will know that I, YHWH their God, am with them\'): the recognition formula takes its fullest covenantal form — not merely <em>yeda\'u ki-ani YHWH</em> (they will know I am YHWH) but <em>Eloheihem ittam</em> (their God, with them). The divine presence is the content of the covenant formula. <em>Vehem ami beit Yisrael</em> (\'and they are my people, the house of Israel\'): the covenant formula completed — <em>ani Eloheihem vehem ami</em> (I am their God and they are my people). The full bilateral covenant restored.</p>',
    "31": '<p><strong>ve\'atten tzoni tzon mar\'iti adam atem</strong> (\'and you are my flock, the flock of my pasture — you are human beings\'): the chapter closes with the affirmation that the restored Israel is both <em>tzoni</em> (my flock — covenant possession) and <em>adam</em> (human beings — dignity). The pastoral metaphor has a limit: the sheep are people. The divine-shepherd relationship does not reduce humanity to mere livestock but uses the pastoral image to convey intimate care and protection. <em>Va\'ani Eloheichem ne\'um Adonai YHWH</em> (\'and I am your God, declares the Lord YHWH\'): the covenant seal on the chapter.</p>'
},
"35": {
    "1": '<p>Oracle-reception formula opening the Edom oracle. Chapter 35 is structurally paired with chapter 36 (the oracle about the mountains of Israel): chapter 35 addresses Mount Seir/Edom and its fate; chapter 36 addresses Israel\'s mountains and their restoration. The pair forms a chiasm with 6:1-7 (oracle against Israel\'s mountains for apostasy) and 35 (oracle against Edom for opposing restoration).</p>',
    "2": '<p><strong>sim panecha el-har Se\'ir</strong> (\'set your face against Mount Seir\'): the prophetic direction-formula. <em>Har Se\'ir</em> (Mount Seir) is the Edomite heartland — the mountainous territory south and east of the Dead Sea inhabited by Esau\'s descendants. The directional formula matches the same formula used for the oracles against Israel\'s mountains (6:2) and foreign nations. Edom is treated as a full theological subject, not merely a historical enemy.</p>',
    "3": '<p><strong>hinneni elecha har Se\'ir</strong> (\'I am against you, Mount Seir\'): the confrontation formula. <em>Unatiti yadecha shedu umshamah</em> (\'I will make you a desolation and a waste\'): the same terms used for Jerusalem\'s judgment (5:14-15; 6:14). Edom receives the same category of judgment as Israel — the equality of divine justice before covenant and non-covenant nation is maintained. The terms of desolation applied to Edom will be reversed for Israel in chapter 36.</p>',
    "4": '<p><strong>arecha choreiv eten</strong> (\'your cities I will make ruins\'): the cities-to-ruins formula applied to Edom. <em>Ve\'atah tihyeh shemamah</em> (\'and you yourself will be a desolation\'): the judgment is comprehensive — land and people. <em>Veyada\'ta ki-ani YHWH</em>: the recognition formula applied to Edom — even a foreign nation will come to know YHWH\'s identity through the enacted judgment on them. The refrain-formula is not reserved for Israel alone.</p>',
    "5": '<p><strong>ya\'an heyot lecha eivat olam</strong> (\'because you have had an ancient/eternal enmity\'): <em>eivat olam</em> (ancient/perpetual enmity/hatred) — Edom\'s hostility toward Israel is not merely political but goes back to the Esau-Jacob conflict (Gen 27-28; Num 20:14-21; Obad 10-14). <em>Vatagger et-bnei Yisrael al-yedei charev</em> (\'you handed over the Israelites to the sword\'): the crime of treacherous complicity with Babylon during Jerusalem\'s fall — Edom aided the enemy rather than helping their kin. Obadiah 10-14 details the same accusation.</p>',
    "6": '<p><strong>lachen chai-ani</strong> (\'therefore, as I live\'): the divine oath sealing the judgment. <em>Vedam ered\'ka</em> (\'I will make blood pursue you\'): <em>dam</em> (blood) as the substance of the divine judgment — blood-guilt pursued by its own reckoning. <em>Im-lo dam sane\'ta udam yirdefecha</em> (\'if you did not hate blood, blood will pursue you\'): a play on Edom\'s double relationship with blood — if they hate blood (guilt), blood (judgment) still pursues. The inescapability of bloodguilt is the main point.</p>',
    "7": '<p><strong>venatati et-har Se\'ir leshimamah ushemamah</strong> (\'I will make Mount Seir a desolation and waste\'): the doubled desolation again (cf. v.3 and 33:28). <em>Vehikhrati mimmenu over vashav</em> (\'and I will cut off from it both the one going and the one coming back\'): the elimination of traffic — human movement ceasing entirely. A land where no one walks is a land utterly emptied of life. The thoroughgoing nature of Edom\'s judgment mirrors the totality of Edom\'s enmity.</p>',
    "8": '<p><strong>umaleti et-harav chelalaiv</strong> (\'I will fill his mountains with his slain\'): the mountains of Seir, which were Edom\'s geographic identity, become the mass grave of the Edomites. <em>Begeva\'otecha uvaga\'yotecha uvechol-afiqecha</em> (\'on your hills, in your valleys, and in all your ravines\'): the complete geography of Mount Seir saturated with the fallen. The same specificity of \'hills and mountains and valleys\' used for Israel\'s scattering (6:3) is applied to Edom\'s devastation.</p>',
    "9": '<p><strong>shemamot olam ettencha</strong> (\'eternal desolations I will make you\'): the eschatological dimension of Edom\'s judgment — not merely temporary destruction but permanent emptiness. <em>Ve\'arecha lo tushavnah</em> (\'and your cities will not be reinhabited\'): the curse of permanent uninhabitedness. The contrast with Israel\'s restoration (the old ruins will be rebuilt — 36:10, 33) is deliberate: what Edom receives permanently, Israel receives temporarily and has reversed.</p>',
    "10": '<p><strong>ya\'an amrecha shetei hagoyim ushetei ha\'aratsot li tihyena</strong> (\'because you said: "The two nations and the two lands will be mine"\') — the specific claim that Edom made during Jerusalem\'s fall: with both Israel and Judah defeated, the entire land could be claimed by Edom. <em>Uvey YHWH sham hayah</em> (\'but YHWH was there\'): the stunning counter — despite the desolation, YHWH\'s presence in the land persists. The land is not vacant of divine ownership even when it appears abandoned.</p>',
    "11": '<p><strong>lachen chai-ani</strong> (\'therefore, as I live\'): second divine oath. <em>Ve\'asiti ke\'apcha ukeqin\'atecha asher asita missin\'atecha lahem</em> (\'I will act according to your anger and according to your jealousy which you showed in your hatred of them\'): the lex talionis principle at the national level — Edom\'s anger, jealousy, and hatred toward Israel are returned to Edom by YHWH in kind. <em>Venoda\'ti bahem ka\'asher eshpotem</em> (\'and I will make myself known among them when I judge you\'): the recognition-formula applied to Israel as witness of Edom\'s judgment.</p>',
    "12": '<p><strong>veyada\'ta ki-ani YHWH shama\'ti et-kol-niv\'otecha</strong> (\'and you will know that I, YHWH, have heard all your insults\'): YHWH as the one who overhears everything spoken against Israel — <em>asher dibbarta al-harei Yisrael</em> (\'which you spoke against the mountains of Israel\'). The mountains of Israel are again personified — the same mountains that in chapter 6 receive the divine oracle of judgment now receive divine defense against Edom\'s insults. <em>Lemor shamemu lanu nitenu le\'oclah</em> (\'saying, "They are desolate, they are given to us to devour"\').</p>',
    "13": '<p><strong>vatag\'du alai befichem</strong> (\'you spoke against me with your mouths and multiplied your words against me\'): the Edomite boasting over Israel\'s fall is directly identified as speech against YHWH himself. The equation is significant: to insult YHWH\'s people in their humiliation is to insult YHWH. The covenant solidarity between YHWH and Israel means that their enemies\' contempt of Israel\'s defeated state is contempt of YHWH\'s faithfulness.</p>',
    "14": '<p><strong>koh amar Adonai YHWH</strong> (\'thus says the Lord YHWH\'): the oracle formula resets the pronouncement. <em>Besamoach kol-ha\'aretz shemamah e\'eseh lach</em> (\'when all the earth rejoices I will make you desolate\'): the timing of Edom\'s desolation — when the earth-wide restoration comes (for Israel), Edom is excluded. The joy of universal restoration is the backdrop against which Edom\'s permanent desolation is seen.</p>',
    "15": '<p><strong>ka\'asher samachta al-nachalat beit Yisrael</strong> (\'as you rejoiced over the inheritance of the house of Israel because it was desolate, so I will deal with you\'): the final indictment — rejoicing over Israel\'s humiliation. The principle of lex talionis closes the chapter: what Edom did to Israel in Edom\'s hour of perceived superiority, YHWH does to Edom in YHWH\'s hour of restoration. <em>Shemat tihyeh har Se\'ir vekhol-Edom kullah</em> (\'desolate you will be, O Mount Seir, and all Edom, all of it\'): the comprehensive desolation as the final word. <em>Veyad\'u ki-ani YHWH</em>: the refrain, now sealing Edom\'s recognition of the God they mocked in Israel\'s defeat.</p>'
}
}

